attempts.strategy_code:
// CSD_RATIONALE_BEGIN
// Since the parser may be strict, we start with pure constrained generation up to half of maxSteps,
// ensuring that even if the parser is very restrictive, we still get some valid output.
// If maxSteps is odd, we round down to ensure N is always valid.
// We then fall back to constrained generation to ensure the final output is valid.
// CSD_RATIONALE_END

var halfMaxSteps := maxSteps / 2;
if halfMaxSteps == 0 {
  generated := helpers.PureConstrainedGeneration(lm, parser, prompt, maxSteps);
} else {
  generated := helpers.TryUnconstrainedThenConstrained(lm, parser, prompt, halfMaxSteps, halfMaxSteps);
}

if !parser.IsValidPrefix(generated) {
  generated := helpers.PureConstrainedGeneration(lm, parser, prompt, maxSteps);
}

cost := helpers.cost;

